import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import edbEn from './locales/en.json';

export const rtlLanguages = ['ar', 'he'];
export const supportedLanguages = ['en'];
export const LANGUAGE_STORAGE_KEY = 'edb-language';
export const changeLanguage = (lng) => i18n.changeLanguage(lng);

export const initializeI18nSync = (initialLanguage = 'en') => {
  i18n
    .use(initReactI18next)
    .init({
      resources: {
        en: { edb: edbEn }
      },
      lng: initialLanguage,
      fallbackLng: 'en',
      ns: ['edb'],
      defaultNS: 'edb',
      interpolation: {
        escapeValue: false
      },
      react: {
        useSuspense: false
      }
    });

  return i18n;
};

export default i18n;
