import { useTranslation } from 'react-i18next';

function trackAppDownload() {
  if (typeof window.gtag === 'function') {
    window.gtag('event', 'app_download', {
      event_category: 'engagement',
      event_label: 'iOS App Store',
      app_id: '6758286241',
    });
  }
}

export default function AppStoreBadges() {
  const { t } = useTranslation('edb');

  return (
    <div className="flex flex-row gap-2 items-center justify-center">
      <a
        href="https://apps.apple.com/us/app/external-display-browser/id6758286241"
        target="_blank"
        rel="noopener noreferrer"
        className="group inline-block hover:scale-105 transition-transform duration-200"
        data-fast-goal="ios_download"
        onClick={trackAppDownload}
      >
        <img 
          src="/app-store-badge.svg" 
          alt={t('appStore.downloadButton')} 
          width={180}
          height={60}
          loading="eager"
          decoding="async"
          style={{ height: '60px', width: 'auto' }}
        />
      </a>
    </div>
  );
}
