// Single iPhone content that morphs between screen-mirroring (bigger bar, side bars) and EDB
const AnimatedIPhoneContent = ({ isBefore }) => {
  const T = '0.6s cubic-bezier(0.4,0,0.2,1)';
  // iPhone mockup SVG is 450×920, inner display is 94%×96% → AR = 423/883.2, H = 2.088×W
  // Rotated landscape div (90° CW):
  //   CSS left/right → becomes phone top/bottom (= dark bars we want to show)
  //   CSS top/bottom → becomes phone left/right (must bleed outside to avoid gaps)
  //   Oversize slightly: width=216% / height=49.5% so phone left/right are always covered.
  //   Inner browser content has CSS left/right margin=8% → phone top/bottom dark bars.
  return (
    <div style={{ position: 'absolute', inset: 0, overflow: 'hidden', background: '#0f172a' }}>
      {/* Normal Screen Mirroring: rotated browser content with top/bottom bars on phone */}
      <div
        style={{
          position: 'absolute',
          width: '216%',
          height: '49.5%',
          left: '-58%',
          top: '25.25%',
          transformOrigin: 'center center',
          transform: 'rotate(90deg)',
          background: 'black',
          display: 'flex',
          flexDirection: 'column',
          opacity: isBefore ? 1 : 0,
          transition: `opacity ${T}`,
          willChange: 'opacity'
        }}
      >
        {/* CSS left/right margin → shows as phone top/bottom dark bars after rotation */}
        <div style={{ flex: 1, margin: '0 8%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          {/* Toolbar */}
          <div style={{
            background: 'rgba(30,41,59,0.92)',
            display: 'flex',
            alignItems: 'center',
            flexShrink: 0,
            padding: '4px 6px',
            gap: '3px',
          }}>
            <div style={{ display: 'flex', gap: '3px', marginTop: '4px' }}>
              {['#ef4444','#eab308','#22c55e'].map((c, i) => (
                <div key={i} style={{ width: '5px', height: '5px', background: c, borderRadius: '50%', flexShrink: 0 }} />
              ))}
            </div>
            <div style={{
              flex: 1,
              background: '#334155',
              borderRadius: '999px',
              padding: '1px 4px',
              marginTop: '4px',
              fontSize: '6px',
              lineHeight: 1.3,
              color: '#cbd5e1',
              overflow: 'hidden',
              whiteSpace: 'nowrap',
              textOverflow: 'ellipsis',
            }}> &nbsp;</div>
          </div>
          {/* Content area */}
          <div style={{ flex: 1, background: 'rgba(8,47,73,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Globe style={{ width: '10px', height: '10px', color: 'rgba(56,189,248,0.4)' }} />
          </div>
        </div>
      </div>

      {/* EDB App: full-screen blue content */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          background: '#0284c7',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          opacity: isBefore ? 0 : 1,
          transition: `opacity ${T}`,
          willChange: 'opacity',
        }}
      >
        <Globe style={{
          width: '16px',
          height: '16px',
          color: 'rgba(255,255,255,0.9)',
        }} />
      </div>
    </div>
  );
};

