import { StrictMode, lazy, Suspense } from 'react'
import { createRoot } from 'react-dom/client'
import { BrowserRouter, Routes, Route } from 'react-router-dom'
import './index.css'
import { initializeI18nSync } from './i18n/config'
import App from './App.jsx'

const BlogIndex = lazy(() => import('./pages/BlogIndex.jsx'));
const BlogExternalMonitor = lazy(() => import('./pages/BlogExternalMonitor.jsx'));
const BlogPortableMonitor = lazy(() => import('./pages/BlogPortableMonitor.jsx'));
const BlogExtendIphoneToTV = lazy(() => import('./pages/BlogExtendIphoneToTV.jsx'));
const BlogSamsungDex = lazy(() => import('./pages/BlogSamsungDex.jsx'));
const BlogNoBlackBars = lazy(() => import('./pages/BlogNoBlackBars.jsx'));

const root = createRoot(document.getElementById('root'));

// Check if we were redirected from 404.html
const redirectPath = sessionStorage.getItem('redirectPath');
if (redirectPath) {
  window.history.replaceState(null, '', redirectPath);
  sessionStorage.removeItem('redirectPath');
}

// Initialize i18n synchronously
initializeI18nSync('en');

const BlogFallback = () => (
  <main className="min-h-screen flex items-center justify-center bg-white dark:bg-slate-900">
    <div className="w-8 h-8 border-4 border-sky-200 border-t-sky-500 rounded-full animate-spin" />
  </main>
);

const BlogRoutes = (
  <Suspense fallback={<BlogFallback />}>
    <Routes>
      <Route path="/blog" element={<BlogIndex />} />
      <Route path="/blog/how-to-use-iphone-with-external-monitor" element={<BlogExternalMonitor />} />
      <Route path="/blog/iphone-portable-monitor-full-screen" element={<BlogPortableMonitor />} />
      <Route path="/blog/best-way-to-extend-iphone-to-tv" element={<BlogExtendIphoneToTV />} />
      <Route path="/blog/samsung-dex-alternative-for-iphone" element={<BlogSamsungDex />} />
      <Route path="/blog/iphone-external-display-no-black-bars" element={<BlogNoBlackBars />} />
      <Route path="/*" element={<App />} />
    </Routes>
  </Suspense>
);

// Render immediately
const AppWrapper = import.meta.env.DEV ? (
  <StrictMode>
    <BrowserRouter>
      {BlogRoutes}
    </BrowserRouter>
  </StrictMode>
) : (
  <BrowserRouter>
    {BlogRoutes}
  </BrowserRouter>
);

root.render(AppWrapper);
